mapper.select:
SELECT pr.*, q.content AS question_content, q.answer AS correct_answer, q.analysis, c.course_name
FROM t_practice_record pr
LEFT JOIN t_question q ON pr.question_id = q.question_id
LEFT JOIN t_course c ON q.course_id = c.course_id
WHERE pr.student_id = #{studentId}

    AND q.course_id = #{courseId}

ORDER BY pr.practice_time DESC

    LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM t_practice_record pr
LEFT JOIN t_question q ON pr.question_id = q.question_id
WHERE pr.student_id = #{studentId}

    AND q.course_id = #{courseId}
